var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"사실은 어렴풋이 알고 있었어.","JPN":"実はうすうすわかっていた。","ENG":"In truth, I somewhat knew.","TWN":"其實我依稀知道，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"이번 의뢰는 어딘가에서부터, 어쩌면 처음부터 어긋나 있었다고.","JPN":"この依頼はどこからか、もしかしたら最初から間違っていたって。","ENG":"That something was off about this job... Maybe even from the beginning.","TWN":"這次的委託不知道從某處開始，或許從一開始就偏離正軌。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"허억…… 헉…… 허억……!","JPN":"はぁっ……はっ……はあ……！","ENG":"*Huff* *Gasp!* *Huff…!*","TWN":"呼呼……呼……呼呼……！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"하아…… 하아……. 드디어 얌전해졌네.","JPN":"はあ……はあ……やっと大人しくなったわね。","ENG":"*Huff... Huff...* So you finally decided to give up, eh?","TWN":"呼呼……呼呼……終於放棄抵抗嗎？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그쪽도 움직이지 마. 지금부터 생길 수 있는 모든 부상은 당신들이 자초한 거야.","JPN":"そっちも動かないで。ここからは怪我をしてもあなたたちの自業自得よ。","ENG":"Don't you dare move either. Any injuries you sustain from now on are entirely your responsibility.","TWN":"你也別動，現在開始，任何可能產生的傷，都是你們自找的。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Krr...","TWN":"唔……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"왜 집까지…… 그러니까, 조직에 증언을…….","JPN":"なんで家まで……つまり、組織に証言したことを……","ENG":"Why... to my house? So... they found out tha─","TWN":"怎麼跑到我家來……意思是作證的事被組織……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WOMAN_EP9HALF_NULL_NULL","text":{"KOREA":"유리야, 유미랑 올라가서 어서 자. 응?","JPN":"ユリ、ユミと一緒に上がって早く寝なさい。ね？","ENG":"Yuri, take Yumi upstairs and go to sleep. Okay, sweetie?","TWN":"悠麗，你和悠美快上去睡覺，嗯？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"왜요? 아빠랑 같이 일하는 사람 아니에요?","JPN":"なんで？　お父さんと一緒に働いてる人じゃないの？","ENG":"But why? Isn't he a policeman too?","TWN":"為什麼？那不是爸爸的同事嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAN_NPC_ALPHA_NULL","text":{"KOREA":"여보, 유리 안 올려 보냈어? 어서 올려 보내.","JPN":"おい、ユリはまだ上がってないのか？　早く行かせろ。","ENG":"Honey, take Yuri upstairs now.","TWN":"老婆，還不叫悠麗上去？快叫她上去！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"결국 나는 겁쟁이였어.","JPN":"結局私は臆病者だった。","ENG":"I was a coward.","TWN":"結果我是個膽小鬼。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"우리 가족을 이런 꼴로 만든 놈이 저 여자처럼 자기 죄를 후회하고 있다면 어떻게 해야 할지.","JPN":"私の家族をこんな風にしたやつがあの女のように罪を後悔しているとしたら、どうするか。","ENG":"Wondering what I would do if that jerk who had destroyed my family regretted his sins, just like her...","TWN":"我害怕，要是殺害我家人的犯人，和那女人一樣對自己的犯行感到後悔的話怎麼辦，"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"무서워서, 견딜 수 없었던 거야.","JPN":"怖くて、耐えられなかったんだ。","ENG":"I was so terrified, I couldn't stand it.","TWN":"我怕到無法承受。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"알고 있어?","JPN":"知ってる？","ENG":"Did you know about this?","TWN":"你知道嗎？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"화기로 무장한 중범죄자가 체포에 불응한다면, 제압 과정에서 <color=#ffd34c>피치 못할</color> 사정으로 사살할 수도 있어.","JPN":"火器で武装した重犯罪者が逮捕に応じない場合、制圧する際に<color=#ffd34c>やむを得ない</color>事情で射殺することもできるの。","ENG":"An armed felon who resists arrest may be killed as a result of the arrest's <color=#ffd34c>unfortunate circumstances</color>.","TWN":"武裝份子若不配合被捕，在逮捕過程中，可基於<color=#ffd34c>不可避</color>之情形開槍射殺。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내가 지금 손 하나 까딱하면……. 당신 인생은 경위서 한 장으로 바뀌게 되는 거야.","JPN":"私が今指一本動かせば……あなたの人生は経緯報告書一枚で変わっちゃうというわけ。","ENG":"With just the slightest movement of my hand... Your life could end, and all I need to do is file a one-page police report.","TWN":"我現在只要一個手滑……你的人生就會立刻成為一份報告書。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"멈출 수 없는 거지. 멈추기에는 너무 늦었어.","JPN":"もう止められないんだ。止まるには遅すぎた。","ENG":"I can't stop. It's too late for that.","TWN":"不能停，現在才收手已經太遲。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"이대로 살아 있어 봤자, 동생을 지켜주긴커녕 짐만 될 뿐이라면…….","JPN":"このまま生きていても、妹を守るどころか足手まといになるだけなら……","ENG":"Even if I carry on with my life like this, I would be more of a burden than a protector to her...","TWN":"繼續這樣活著，不要說保護妹妹，反而只會成為她的包袱……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"차라리 여기서…….","JPN":"いっそここで……","ENG":"If that's the case, then maybe I should...","TWN":"那不如乾脆就此……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……자, 수갑은 직접 차시지. 민병대.","JPN":"……ほら、手錠は自分の手でかけなさい。民兵隊。","ENG":"...Here, I'm sure you can put these cuffs on yourselves, no?","TWN":"……拿去，自己上銬吧，民兵隊。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L35_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐……?","JPN":"は……？","ENG":"Huh...?","TWN":"什麼……？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내 말 안 들려? 수갑 차라고 했어.","JPN":"聞こえなかった？　手錠、かけなさいって言ったの。","ENG":"Didn't you hear me? Put on the cuffs.","TWN":"沒聽到我說的嗎？叫你上銬。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"미안하지만……. 살려 준다고 해서 용서 따위 빌 생각 없어.","JPN":"悪いけど……生かしてもらったからって許しを請うつもりなんてない。","ENG":"I'm sorry to tell you, but... Just because you let me live doesn't mean I’ll beg for your forgiveness.","TWN":"不好意思……我可不會因為你不殺我就祈求原諒。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"착각하지 마. 당신들 같은 족속이 변할 수 있다고 생각하지 않아.","JPN":"勘違いしないで。あなたたちのような部類が変わるとは思わないわ。","ENG":"Don't get me wrong. I don't believe people like you can change.","TWN":"別誤會，我可不想成為和你們同類的人。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"여기서 당신들을 죽여 봤자 불공평한 정의에 희생된 순교자로 만들어 줄 뿐이니까.","JPN":"ここであなたたちを殺しても、不公平な正義の犠牲になった殉教者を作ったことにしかならないわ。","ENG":"Killing you here will only make you martyrs sacrificed in the hands of unfair justice.","TWN":"在這裡殺掉你，只會把你們塑造成在非法正義下犧牲的烈士。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이유미, 경정…….","JPN":"カスカベ・ユミ、警視……","ENG":"Major... Lee Yumi...","TWN":"李悠美警正……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"당신들에게 동정심 따위는 없어.","JPN":"あなたたちに同情なんてしないわ。","ENG":"I have no sympathy for you.","TWN":"我不需要你的同情。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경찰 내부에서 날 보는 시선은 잘 알고 있어. 내 손에 피를 묻히면 혼수 상태인 경위의 체면에도 먹칠을 하게 되겠지.","JPN":"警察の内部で私をどう見てるかはよくわかってる。私の手を血に染めれば昏睡状態になった警部補の顔にも泥を塗ることになるでしょう。","ENG":"And I know how people look at me in the force. One drop of blood on my hands, and they'll be tarnishing my reputation as well as the lieutenant’s.","TWN":"我知道警察內部是怎麼看我的，要是我的手染血，連帶也有損還在昏迷中姜素英員警的面子。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>민병대는 카운터 범죄의 피해자들이 만든 조직이다.</color> 였지?","JPN":"<color=#ffd34c>民兵隊はカウンター犯罪の被害者が作った組織</color>だったわね？","ENG":"<color=#ffd34c>The Militia is an organization created by victims of Counter crime</color>, right?","TWN":"<color=#ffd34c>民兵隊是制裁者犯罪受害者組成的組織</color>對吧？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그러니까 어디 당신들이 당한 일을 하나부터 열까지 전부, 사실대로 말해 봐.","JPN":"だからあなたたちが受けた被害を一から十まで全部、ありのまま話してみなさい。","ENG":"Then how about you start telling me the truth about how you're all victims?","TWN":"我要把你們把遭遇過的事情，一五一十地完全交代清楚。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"제대로 처벌하고 난 다음에 당신들을 벌하면 아무도 허튼 소리 못하겠지.","JPN":"そいつらをちゃんと処罰した後にあなたたちを罰しても、誰も文句は言えないでしょ？","ENG":"I'm sure no one will be able to say anything if I punish the assailants properly and then penalize you.","TWN":"等我懲罰完那些人再懲罰你們，那你們應該就無話可說吧！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"꺄아악!?","JPN":"きゃああっ！？","ENG":"Kyaaaah?!","TWN":"呃啊啊！？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_STING_BIG"},{"id":"L1_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이유미!!","JPN":"カスカベ・ユミ！！","ENG":"Lee Yumi!!","TWN":"李悠美！！"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"방금 뭐야! 대장이 한 짓이야?!","JPN":"今のは何だ！　隊長がやったのか！？","ENG":"What was that?! Captain did you do that?!","TWN":"剛剛是怎麼回事！是隊長幹的嗎？！"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"환자에게 많은 걸 바라는군……! 저쪽이다……!","JPN":"俺は怪我人だぞ……！　あっちだ……！","ENG":"Aren't you expecting too much from an injured person? Look, over there...!","TWN":"你對一個病人會不會要求太多……！那邊……！"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"휴, 하마터면 경찰에게 죽을 뻔했네요, 유리 언니.","JPN":"ふう、危うく警察に殺されるところでしたね、ユリさん。","ENG":"Phew! You almost died to the police there, Yuri.","TWN":"呼，悠麗姊姊，你差點就死在警察手裡咧！"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"제때 와서 다행인 거 있죠?","JPN":"間に合ってよかったでしょ？","ENG":"Aren't you glad I arrived just in time to save you?","TWN":"我來得正好對吧？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"레비아……?","JPN":"レヴィア……？","ENG":"Levia...?","TWN":"莉維亞……？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"너…… 그 애는 어떻게 된 거야?","JPN":"お前……その子は何だ？","ENG":"What... are you doing with that kid?","TWN":"你……那孩子是怎麼回事？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"앗, 이거요?","JPN":"あっ、これですか？","ENG":"Oh, this little girl?","TWN":"喔～這個喔？"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"얘가 제 동생이에요, 언니! 이름은 오르카!","JPN":"この子が私の妹なんですよ！　名前はオルカ！","ENG":"She's my little sister, Yuri! Her name is Orca!","TWN":"她是我的妹妹！她叫奧爾卡！"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"……였던 거, 라고 해야 하나? 에헷.","JPN":"……だったもの、って言うか。えへっ。","ENG":"...Or should I say... \\"was\\" her name? Hehe.","TWN":"……之前是這個名字啦，嘿嘿。"},"stage":{"bg":"TERRA","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};